/** @since 5.0 */
export type State = "ready" | "disabled";

/** @since 5.0 */
export type Direction = "vertical" | "horizontal";

/**
 * The visible elements that are displayed within the widget.
 * This provides the ability to turn individual elements of the widget's display on/off.
 *
 * @since 5.0
 */
export interface VisibleElements {
  /**
   * Indicates whether the handle from which you drag the widget is visible.
   * Default value is `true`.
   *
   * @default true
   * @since 5.0
   */
  handle?: boolean;
  /**
   * Indicates whether the divider between the leading and trailing layers is visible.
   * Default value is `true`.
   *
   * @default true
   * @since 5.0
   */
  divider?: boolean;
}